#include<bits/stdc++.h>
using namespace std;
struct node
{
    int w,v,h;
    bool operator<(const node&b)const
    {
        return v+w<b.v+b.w;
    }
}a[101];
int main()
{
    int n,h;
    scanf("%d%d",&n,&h);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d",&a[i].h,&a[i].w,&a[i].v);
    }
    sort(a+1,a+1+n);
    int ans=-1;
    for(int i=1;i<(1<<n);i++)
    {
        vector<node> v;
        int sum=0;
        for(int j=1;j<=n;j++)
        {
            if(i&(1<<(j-1)))
            {
                sum+=a[j].h;
                v.push_back(a[j]);
            }
        }
        if(sum>=h)
        {
            sort(v.begin(),v.end());
            reverse(v.begin(),v.end());
            int now=1e9,min1=1e9;
            for(auto i:v)
            {
                now=min(now-i.w,i.v);
                min1=min(min1,now);
            }
            ans=max(ans,min1);
        }
    }
    if(ans==-1)
    {
        printf("Mark is too tall");
    }
    else
    {
        printf("%d",ans);
    }
    return 0;
}
